content.query:
let pages = customMetrics
| where timestamp {TimeRange}
| where name == "transpose.ocr.pages_processed"
| summarize total_pages = sum(value);
let chunks = customMetrics
| where timestamp {TimeRange}
| where name == "transpose.pipeline.chunks_translated"
| summarize total_chunks = sum(value);
let tokens = customMetrics
| where timestamp {TimeRange}
| where name == "transpose.openai.tokens_used"
| summarize total_tokens = sum(value);
let errs = customMetrics
| where timestamp {TimeRange}
| where name == "transpose.errors"
| summarize total_errors = sum(value);
pages | extend dummy = 1
| join kind=fullouter (chunks | extend dummy = 1) on dummy
| join kind=fullouter (tokens | extend dummy = 1) on dummy
| join kind=fullouter (errs | extend dummy = 1) on dummy
| project Pages_Processed = total_pages, Chunks_Translated = total_chunks, Tokens_Used = total_tokens, Total_Errors = total_errors

// Container App CPU and Memory from performanceCounters or customMetrics
// These are emitted by the azure-monitor-opentelemetry SDK
performanceCounters
| where timestamp {TimeRange}
| where category == "Process" or name has "cpu" or name has "memory" or name has "CPU" or name has "Memory"
| summarize avg_value = avg(value) by name, bin(timestamp, 5m)
| order by timestamp asc
